import {
  mkdir,
  readFile,
  readdir,
  rename,
  rm,
  writeFile,
} from 'node:fs/promises';
import path from 'node:path';

export const OPEN_PROBLEM_GENERATED_PAGE_MARKER =
  '{/* GENERATED BY scripts/generate-open-problem-pages.mjs. DO NOT EDIT. */}';

function yamlString(value) {
  return JSON.stringify(value);
}

function detailPageSource(problem) {
  return `---
title: ${yamlString(problem.title)}
description: ${yamlString('Verified open-problem record for ' + problem.title + '.')}
---

${OPEN_PROBLEM_GENERATED_PAGE_MARKER}

import OpenProblemDetail from '../../../../../components/OpenProblemDetail.astro';

<OpenProblemDetail problemId=${yamlString(problem.id)} />
`;
}

export function createGeneratedOpenProblemPages(problems) {
  return new Map(
    problems.map((problem) => [
      path.join(problem.id, 'index.mdx'),
      detailPageSource(problem),
    ]),
  );
}

async function collectFiles(directory) {
  let entries;
  try {
    entries = await readdir(directory, { withFileTypes: true });
  } catch (error) {
    if (error?.code === 'ENOENT') {
      return [];
    }
    throw error;
  }
  const files = [];
  for (const entry of entries) {
    const target = path.join(directory, entry.name);
    if (entry.isDirectory()) {
      files.push(...(await collectFiles(target)));
    } else {
      files.push(target);
    }
  }
  return files;
}

function normalizeLineEndings(source) {
  return source.replace(/\r\n/g, '\n');
}

function resolveContainedTarget(outputDirectory, relativePath) {
  const root = path.resolve(outputDirectory);
  const target = path.resolve(root, relativePath);
  if (target !== root && !target.startsWith(root + path.sep)) {
    throw new Error(
      'Generated open-problem page path escapes the output directory: ' +
        relativePath,
    );
  }
  return target;
}

async function readExistingSource(file) {
  try {
    return await readFile(file, 'utf8');
  } catch (error) {
    if (error?.code === 'ENOENT') {
      return null;
    }
    throw error;
  }
}

async function writeFileAtomically(target, source) {
  const temporaryPath =
    target + '.' + process.pid + '.' + Date.now() + '.generated.tmp';
  try {
    await writeFile(temporaryPath, source, 'utf8');
    await rename(temporaryPath, target);
  } catch (error) {
    await rm(temporaryPath, { force: true });
    throw error;
  }
}

export async function synchronizeGeneratedOpenProblemPages(
  outputDirectory,
  pages,
  { check = false } = {},
) {
  const expectedPaths = new Set(pages.keys());
  const existingFiles = await collectFiles(outputDirectory);
  const issues = [];
  const staleFiles = [];

  for (const file of existingFiles) {
    const relativePath = path.relative(outputDirectory, file);
    const source = normalizeLineEndings(await readFile(file, 'utf8'));
    if (!source.includes('\n' + OPEN_PROBLEM_GENERATED_PAGE_MARKER + '\n')) {
      issues.push(
        relativePath +
          ': unowned file is inside the generated open-problem directory',
      );
    } else if (!expectedPaths.has(relativePath)) {
      staleFiles.push(file);
      if (check) {
        issues.push(relativePath + ': stale generated open-problem page');
      }
    }
  }

  for (const [relativePath, expectedSource] of pages) {
    const target = resolveContainedTarget(outputDirectory, relativePath);
    const actualSource = await readExistingSource(target);
    if (actualSource === null) {
      if (check) {
        issues.push(relativePath + ': generated open-problem page is missing');
      }
    } else if (
      check &&
      normalizeLineEndings(actualSource) !== normalizeLineEndings(expectedSource)
    ) {
      issues.push(relativePath + ': generated open-problem page is out of date');
    }
  }

  if (issues.length > 0) {
    return { ok: false, issues, written: 0, removed: 0 };
  }
  if (check) {
    return { ok: true, issues: [], written: 0, removed: 0 };
  }

  await mkdir(outputDirectory, { recursive: true });
  for (const file of staleFiles) {
    await rm(file, { force: true });
  }

  let written = 0;
  for (const [relativePath, source] of pages) {
    const target = resolveContainedTarget(outputDirectory, relativePath);
    const actualSource = await readExistingSource(target);
    if (
      actualSource !== null &&
      normalizeLineEndings(actualSource) === normalizeLineEndings(source)
    ) {
      continue;
    }
    await mkdir(path.dirname(target), { recursive: true });
    await writeFileAtomically(target, source);
    written += 1;
  }

  return {
    ok: true,
    issues: [],
    written,
    removed: staleFiles.length,
  };
}
